import "../Stylesheets/Menu.css";
import Conteudo from "./Conteudo";

export default function Menu() {
  return (
    <>
      <div className="w-full h-24 py-5 inline-flex justify-between items-center shadow-2xl">
        <a
          className="inline-flex text-4xl font-sans font-bold bg-yellow-300 h-fit ml-[5%]"
          href="#"
        >
          Corrida dos DEVs
          <img src="logo.svg" alt="Corrida-dos-devs-logo" />
        </a>
        <ul className="nav-list">
          <li><a>Ranking</a></li>
          <li><a>Registr</a></li>
          <li><a>Ranking</a></li>
        </ul>
      </div>
      <Conteudo></Conteudo>
    </>
  );
}
